-- ─── CHECKLIST ITEMS ───────────────────────────────────────
INSERT OR IGNORE INTO ess_checklist_items (id, section_id, label, sort_order) VALUES
  ('ess_i2_01', 'ess_s2_1', 'Define species, population, community, ecosystem, biome, and biosphere', 1),
  ('ess_i2_02', 'ess_s2_1', 'Explain the niche concept (fundamental vs realized niche)', 2),
  ('ess_i2_03', 'ess_s2_1', 'Distinguish between habitat and niche', 3),
  ('ess_i2_04', 'ess_s2_1', 'Describe biotic and abiotic factors that affect ecosystems', 4),
  ('ess_i2_05', 'ess_s2_1', 'Explain the different types of species interactions: competition, predation, parasitism, mutualism, commensalism', 5),
  ('ess_i2_06', 'ess_s2_2', 'Describe how energy flows through an ecosystem via food chains and food webs', 6),
  ('ess_i2_07', 'ess_s2_2', 'Explain trophic levels and the 10% rule of energy transfer', 7),
  ('ess_i2_08', 'ess_s2_2', 'Define and calculate gross primary productivity (GPP), net primary productivity (NPP), and respiration (R)', 8),
  ('ess_i2_09', 'ess_s2_2', 'Explain GPP = NPP + R and its significance', 9),
  ('ess_i2_10', 'ess_s2_2', 'Construct and interpret pyramids of numbers, biomass, and productivity', 10),
  ('ess_i2_11', 'ess_s2_3', 'Describe the carbon cycle including storages and flows', 11),
  ('ess_i2_12', 'ess_s2_3', 'Describe the nitrogen cycle including the roles of nitrogen-fixing, nitrifying, and denitrifying bacteria', 12),
  ('ess_i2_13', 'ess_s2_3', 'Explain the process of ecological succession (primary and secondary)', 13),
  ('ess_i2_14', 'ess_s2_3', 'Distinguish between pioneer and climax communities', 14),
  ('ess_i2_15', 'ess_s2_3', 'Explain how biodiversity changes during succession', 15),
  ('ess_i2_16', 'ess_s2_4', 'Describe the characteristics of different biomes (tropical rainforest, desert, tundra, etc.)', 16),
  ('ess_i2_17', 'ess_s2_4', 'Explain how limiting factors affect population growth (carrying capacity)', 17),
  ('ess_i2_18', 'ess_s2_4', 'Describe S-curve and J-curve population growth patterns', 18),
  ('ess_i2_19', 'ess_s2_4', 'Explain the concept of maximum sustainable yield', 19),
  ('ess_i2_20', 'ess_s2_4', 'Describe how biomagnification and bioaccumulation affect food chains', 20);

-- ─── FLASHCARD TOPIC ───────────────────────────────────────
INSERT OR IGNORE INTO ess_flashcard_topics (id, name, description, unit, card_count, sort_order, color) VALUES
  ('ess_t2', 'Ecosystems & Ecology', 'Key terms and concepts from Unit 2: Species, Populations and Ecosystems, Energy Flow and Productivity, Nutrient Cycling, Succession, and Communities and Biomes', '2', 19, 2, '#06B6D4');

-- ─── FLASHCARDS ────────────────────────────────────────────
INSERT OR IGNORE INTO ess_flashcards (id, topic_id, front, back, sort_order) VALUES
  ('ess_f2_01', 'ess_t2', 'Species', 'A group of organisms that can interbreed and produce fertile offspring.', 1),
  ('ess_f2_02', 'ess_t2', 'Population', 'A group of organisms of the same species living in the same area at the same time.', 2),
  ('ess_f2_03', 'ess_t2', 'Community', 'A group of populations of different species living and interacting in the same area.', 3),
  ('ess_f2_04', 'ess_t2', 'Ecosystem', 'A community of interdependent organisms and the physical environment they inhabit, linked by energy flows and nutrient cycling.', 4),
  ('ess_f2_05', 'ess_t2', 'Biome', 'A large-scale ecosystem defined by its climate, soil, and characteristic plant and animal communities. Examples: tropical rainforest, tundra, desert.', 5),
  ('ess_f2_06', 'ess_t2', 'Trophic Level', 'The position an organism occupies in a food chain. Producers (T1), primary consumers (T2), secondary consumers (T3), tertiary consumers (T4).', 6),
  ('ess_f2_07', 'ess_t2', 'GPP (Gross Primary Productivity)', 'The total amount of energy fixed by photosynthesis per unit area per unit time. Measured in kJ m⁻² yr⁻¹.', 7),
  ('ess_f2_08', 'ess_t2', 'NPP (Net Primary Productivity)', 'The energy remaining in plant biomass after respiration: NPP = GPP - R. This is the energy available to consumers.', 8),
  ('ess_f2_09', 'ess_t2', '10% Rule', 'On average, only about 10% of energy at one trophic level is transferred to the next level. The rest is lost as heat through respiration.', 9),
  ('ess_f2_10', 'ess_t2', 'Ecological Niche', 'The role and position a species has in its environment, including all interactions with biotic and abiotic factors.', 10),
  ('ess_f2_11', 'ess_t2', 'Primary Succession', 'The development of a community in a lifeless area with no soil, such as bare rock or a new volcanic island.', 11),
  ('ess_f2_12', 'ess_t2', 'Secondary Succession', 'The re-establishment of a community in an area where soil remains after a disturbance, such as after a fire or clearing.', 12),
  ('ess_f2_13', 'ess_t2', 'Pioneer Species', 'The first organisms to colonize a barren area during succession. They are hardy, tolerant of extreme conditions (e.g., lichens, mosses).', 13),
  ('ess_f2_14', 'ess_t2', 'Climax Community', 'The stable, self-sustaining community that develops at the end of ecological succession.', 14),
  ('ess_f2_15', 'ess_t2', 'Carrying Capacity (K)', 'The maximum population size that an environment can sustain indefinitely given the available resources.', 15),
  ('ess_f2_16', 'ess_t2', 'Bioaccumulation', 'The build-up of a persistent substance (e.g., DDT, mercury) in an organism over its lifetime from its environment.', 16),
  ('ess_f2_17', 'ess_t2', 'Biomagnification', 'The increase in concentration of a persistent substance through successive trophic levels of a food chain.', 17),
  ('ess_f2_18', 'ess_t2', 'Carbon Cycle', 'The biogeochemical cycle of carbon through atmosphere, biosphere, hydrosphere, and lithosphere via photosynthesis, respiration, decomposition, combustion, and ocean absorption.', 18),
  ('ess_f2_19', 'ess_t2', 'Nitrogen Fixation', 'The conversion of atmospheric nitrogen (N2) into ammonia (NH3) or nitrates by nitrogen-fixing bacteria (Rhizobium) or lightning.', 19);

-- ─── MCQ QUESTIONS ─────────────────────────────────────────
INSERT OR IGNORE INTO ess_mcq_questions (id, question, options, correct_answer, explanation, category, difficulty, unit) VALUES
  ('ess_m2_01', 'What is the best definition for a species?', '["A group of individuals living in a defined area.","A group of individuals of the same species living and interacting with one another in a given area.","A group of individuals living in a given area and interacting within the environment.","A group of individuals that can interbreed and produce fertile offspring."]', 3, 'A group of individuals living in a defined area is not a biological definition (Option A). A group of individuals of the same species living in a given area at the same time who are interacting with each other is a population (Option B).', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_02', 'Crabs, earthworms, mites and snails feed on the remains of dead plants and animals. State the name of organisms that feed this way.', '["Autotrophs","Consumers","Detritivores","Saprotrophs"]', 2, 'Autotrophs are producers (Option A) which synthesize their own organic compounds. Consumers gain their nutrition by feeding (Option B) on other organisms. Detritivores consume dead organic matter (Option C) by ingestion. Saprotrophs secrete enzymes externally.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_03', 'The Arctic cod, ringed seal, killer whale, polar bear and other organisms live and interact with each other in the cold waters of the Arctic Ocean. State the best term to describe them.', '["Population","Community","Habitat","Ecosystem"]', 1, 'A community is a group of populations living and interacting in a shared habitat (biotic factors). The abiotic factors for this community have not been described but could be the depth of the water, light intensity and the nutrients.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_04', 'State in what form energy is lost from ecosystems.', '["Lost as light","Lost as heat","Lost as carbon dioxide","Lost as chemical energy"]', 1, 'When organisms respire, they lose energy in the form of heat. This form of energy cannot be recovered and is finally lost from the system. Initially, during photosynthesis, energy is captured from light (Option A). Carbon dioxide is matter not energy (Option C).', 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_05', 'State the name of the process that converts carbon dioxide in the air to carbohydrates.', '["Respiration","Photosynthesis","Decomposition","Transpiration"]', 1, 'Photosynthesis (Option B) is the process by which carbon dioxide in the air is converted to carbon compounds in green plants. Respiration releases carbon dioxide (Option A), and decomposition by decomposers (Option C) also releases CO2.', 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_06', 'A biome has: Temperature range -40 to 40 °C, Annual precipitation less than 250 mm, Net primary productivity Low. Deduce the biome represented.', '["Tropical rainforest","Temperate rainforest","Desert","Tundra"]', 2, 'Forests receive higher annual precipitation than 25 cm, thus option A and B are incorrect. A tundra biome would not reach 40 °C, thus option D is incorrect. The desert biome reaches very cold temperatures at night, especially in winter.', 'Communities and Biomes', 'easy', '2'),
  ('ess_m2_07', 'Identify the average monthly rainfall (mm) for Rome in March.', '["70.3","10.2","115.4","24.5"]', 0, 'March is the third month of the year, so choose the third column, which represents average rainfall.', 'Communities and Biomes', 'easy', '2'),
  ('ess_m2_08', 'Rainforests are known to have tall trees and a large biomass with high productivity, despite infertile soils. The growing conditions have been known to nurture the presence of many interdependent organisms. These species also interact with the physical environment they inhabit. Deduce which of the following is described here.', '["A habitat","An ecosystem","A population","A community"]', 1, 'An ecosystem refers to an area where organisms interact with each other and with the physical environment. A habitat (Option A) refers to the environment in which a species normally lives. A population (Option C) is a group of organisms of the same species.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_09', 'Identify the statement that is a correct description of a food chain.', '["The most abundant organisms in a food chain are the secondary consumers.","Autotrophs are producers and form the base of the food chain.","Energy enters a food chain via tertiary consumers.","The flow of energy is from secondary consumers to primary consumers to producers."]', 1, 'Autotrophs are producers and form the base of food chains. They carry out photosynthesis and get their energy from the Sun. The most abundant organisms (Option A) are usually the producers but there are exceptions. Energy always enters a food chain via producers.', 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_10', 'Name the correct units for representing productivity in an ecosystem.', '["g m","g yr","J m","g m"]', 3, 'Productivity shows the flow of energy and is therefore measured as g m⁻² yr⁻¹ OR J m⁻² yr⁻¹. Biomass shows a standing crop and is therefore measured as g m⁻².', 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_11', 'State the abiotic factor that can be measured using a Secchi disk.', '["depth","turbidity","pH","particle size"]', 1, 'A Secchi disk is used to measure the turbidity of freshwater, so option B is correct. If you can still see the Secchi disk when it is deeper, it means that the water has less material floating in it: the turbidity is low.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_12', 'State which of the following sampling techniques is not effective for sampling motile (moving) specimens.', '["Capture-mark-recapture","Sweep nets","Quadrat sampling","Pit traps"]', 2, 'Option C is correct as quadrats are laid down in one place and thus are not useful or accurate in sampling creatures that can easily enter or leave a sample square. Each of the other three options are used specifically for moving creatures.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_13', 'List three factors that could describe a species'' niche.', '["predators","prey","herbivores","speciation"]', 0, 'Niche: the set of resources, abiotic and biotic factors in which a species can survive and the interactions that it has with them. Abiotic factors: physical parts of an environment, e.g. altitude, salinity, precipitation and temperature.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_14', 'Some fungi obtain nutrients by releasing digestive enzymes into their surroundings. The enzymes break down things such as dead and decaying leaves, and the fungi then absorb the products. State the terms that best describe these fungi.', '["Autotrophic detritivores.","Autotrophic saprotrophs.","Heterotrophic detritivores.","Heterotrophic saprotrophs."]', 3, 'Autotrophs are producers (Options A, B). They are self-feeding whereas heterotrophs are organisms that gain nutrition by feeding on other organisms (Options C, D). Detritivores consume dead organic matter by ingestion (Option C).', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_15', 'A rice cultivation system eliminates the need for fertilizers, herbicides and pesticides by using ducks in the organic cultivation of rice. In addition, Azolla, an aquatic floating fern, is grown on these fields because it harbours blue-green algae which can fix atmospheric nitrogen. Which option includes two of the autotrophs in the system?', '["Azolla","Azolla","Rice and fish","Fish and ducks"]', 0, 'Ducks and fish are consumers (Options B, C and D), which is a type of heterotroph, whereas Azolla and rice can carry out photosynthesis and are, therefore, autotrophs (self-feeding).', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_16', 'State the units used for pyramids of energy.', '["Calories","Kilocalories","k","k"]', 3, 'Calories (option A) and kilocalories (option B) are measures for energy but do not include area and time, which is how productivity is measured in an ecosystem. Option C does include the area but not the time. To see energy values option D is correct.', 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_17', 'Identify the statements that describe the use of DDT as an insecticide. I. Certain chemicals tend to concentrate in higher trophic levels of the food chain. II. DDT is a chemical that can be added to water bodies to control mosquito larvae. III. Populations most affected by DDT due to biomagnification were fish and birds; therefore, this chemical has been banned in some countries.', '["I, II and III","I and III only","I and II only","III only"]', 0, 'All the statements show how DDT, when added to water bodies, can be transferred to the top carnivores in an ecosystem. It is concentrated in the tissues of organisms along the transfer, and this process is called biomagnification.', 'Communities and Biomes', 'easy', '2'),
  ('ess_m2_18', 'There is continuous cycling of carbon from the atmosphere to other carbon sinks. Identify the main source of energy for the carbon cycle.', '["Heat","Sunlight","Chemical energy","Energy from respiration"]', 1, 'Energy from the sun (Option B) is used to form carbon compounds through the process of photosynthesis. Heat (Option A) is a form of energy that cannot be converted to chemical energy by living things. Chemical energy (Option C) is a product of photosynthesis.', 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_19', 'Describe the concept of zonation by choosing one or more statements from the following. I. Zonation is the changes in communities along an ecological gradient such as changes in altitude up a mountainside. II. Zonation is normally studied using transect methods along the environmental gradient. III. Environmental changes as applicable to zonation are linear changes of biotic or abiotic factors. Distinct communities form as these factors change.', '["Statement I only","Statement I and II only","Statement I, II and III","Statement III only"]', 2, 'All the statements are correct and applicable to the term zonation.', 'Communities and Biomes', 'easy', '2'),
  ('ess_m2_20', 'Which of the following is not a method of keeping a controlled variable at a constant value throughout this particular experiment?', '["Placing the tube containing","Using the same volume of sodium hydrogen carbonate solution for each trial.","Placing the","Using the same concentration of sodium hydrogen carbonate solution for each trial."]', 0, 'Since the experiment is about testing the temperature, the temperature would be the independent variable, not the controlled variable. A water bath would be used in this experiment to set up different increments of the independent variable.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_21', 'Label the device indicated by the arrow in the Figure.', '["A line transect","A dichotomous key","A quadrat","A Cartesian plane"]', 2, 'The item in the picture is a quadrat square, so option C is the correct choice. Option A is a sampling method using a long line cutting across the sample space and is often used together with quadrats. Option B is an identification key.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_22', 'Schistosoma species: The figure shows the life cycle of a flatworm of the genus Schistosoma. It spends part of its life in a species of ramshorn snail and part of its life in humans. It feeds on these hosts. State the type of interaction between the human and the flatworm.', '["Mutualism","Parasitism","Disease","Predation"]', 1, 'The flatworm is a parasite (Option B) of the human as it feeds on the human without providing a benefit to the human. In mutualism (Option A) both organisms would benefit, e.g. the honeybee and the appletree.', 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_23', 'Suggest a possible conclusion from this graph.', '["There is more carbon dioxide produced at","The rate of photosynthesis increases with temperature.","The maximum amount of oxygen is produced at","The concentration of carbon dioxide is a limiting factor at"]', 2, 'Photosynthesis is a process where organic compounds are produced in cells using light energy, carbon dioxide and water. A product of photosynthesis is oxygen gas. Hence, the rate of photosynthesis can be measured by the rate of carbon dioxide uptake or oxygen produced.', 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_24', 'A rice cultivation system produces duck, fish and rice for human consumption. Draw a possible food chain for the rice cultivation system shown in the image.', '["algae","algae","insects","insects"]', 0, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_25', 'Determine which of the pyramids could be a pyramid of productivity (in kJ m⁻² yr⁻¹).', '["","","",""]', 2, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_26', 'Identify the processes in the carbon cycle that requires the longest time.', '["Compounds present in plankton and plants turn into fossil fuels.","Respiration breaks down organic compounds into carbon dioxide.","Photosynthesis captures solar energy and fixes","Forest fires, which occur naturally and burn the underbrush clean the forest floor of debris."]', 0, NULL, 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_27', 'The okapi looks like a small-sized giraffe and has stripes that resemble the zebra. It lives in the Ituri Forest in the Democratic Republic of the Congo. Okapis eat the leaves and buds of trees they can reach. They also graze on grass and ferns and eat fruit. Which of the following statements is applicable to the okapi? I. Okapi is a hybrid of a giraffe and a zebra II. Okapi is an herbivore III. Okapi is its own species', '["I only","I and II only","II and III only","I and III only"]', 2, NULL, 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_28', 'Determine which of the groups of organisms is a population.', '["The reindeer (","The chimpanzees (","The clownfish (","The red-eyed tree frogs ("]', 3, NULL, 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_29', 'Identify the incorrect description of energy flow in a terrestrial ecosystem.', '["Trophic relationships between plants and animals do not exist as a simple chain, but tend to be more elaborate and interwoven as a food web.","In food webs, different herbivores may feed on the same plant. Also, the same species of herbivore may feed on different plants.","Consumers which feed on the dead remains of plants and animals are called detritivores.","In food webs, a typical food chain consists of approximately 6 organisms."]', 3, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_30', 'State which organism is both a secondary and a tertiary consumer.', '["Harbour seal","Polar bear","Arctic cod","Capelin"]', 2, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_31', 'Zooxanthellae are algae that live inside coral. Corals feed on the carbon compounds produced by zooxanthellae from carbon dioxide, water, and sunlight. State the method of nutrition of these organisms.', '["Autotroph","Autotroph","Heterotroph","Detritivore"]', 0, NULL, 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_32', 'Consider the following chemical reaction: Identify which of the following is not represented by this reaction.', '["Photosynthesis","Cellular respiration","A process occurring in the chloroplasts of plants","Simple sugar production"]', 1, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_33', 'Draw a food chain from the food web shown in the Figure.', '["Phytoplankton ← herbivorous zooplankton ← arctic cod ← polar bear","Phytoplankton → herbivorous zooplankton → arctic cod → polar bear","Carnivorous zooplankton ← arctic cod ← harbour seal ← polar bear","Carnivorous zooplankton → arctic cod → harbour seal → polar bear"]', 1, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_34', 'Distinguish photosynthesis and respiration correctly from the options below.', '["no transformations of energy and matter in the process","glucose is broken down into carbon dioxide and water","carbon dioxide + water → glucose + oxygen","takes place only in green plants"]', 2, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_35', 'Estimate the percentage of energy from the producers reaches the tertiary consumers.', '["100","10","1","0.1"]', 3, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_36', 'Identify the statements that are true. I. Living organisms release energy from organic compounds and convert it to heat during the process of respiration. II. Since heat cannot be transformed into other forms of energy it is lost from ecosystems. III. Light energy from the sun is converted to chemical energy by producers and then converted to heat during respiration.', '["I only","I and II","I and III","I, II and III"]', 3, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_37', 'State how Net Secondary Productivity (NSP) can be calculated.', '["NSP = GPP - R","NSP = food eaten - fecal loss","NSP = GPP + R","NSP = GSP - R"]', 3, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_38', 'Identify which of the following correctly matches the Roman numerals on the figure with the process. I II III IV', '["Respiration","Death and Decomposition","Photosynthesis","Photosynthesis"]', 3, NULL, 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_39', 'Biomes are characterized by climatic patterns and other physical variables. List the main factors that characterize the terrestrial biomes.', '["Temperatures and annual precipitation","Soil characteristics and precipitation","Wind patterns and type of vegetation","Altitude and proximity to water"]', 0, NULL, 'Communities and Biomes', 'easy', '2'),
  ('ess_m2_40', 'With reference to the figure, identify the processes involved in the carbon cycle. I II III IV', '["Respiration","Decomposition","Photosynthesis","Photosynthesis"]', 3, NULL, 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_41', 'State which of the following terms best describes organisms like earthworms that ingest and then break down and digest non-living organic materials.', '["Detritivores","Decomposers","Parasites","Saprotrophs"]', 0, NULL, 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_42', 'Using the Figure, calculate the amount of increase in ppm of toxins from the algae to the fisherman.', '["13.55","13.59","13.51","2.71"]', 2, NULL, 'Communities and Biomes', 'easy', '2'),
  ('ess_m2_43', 'Identify which of the following statements is false when discussing a pyramid of biomass.', '["It is a measure of the mass of the living things in an area.","It is generally a proper pyramid shape.","It follows the 10% rule moving up the trophic levels.","It is measured in g m"]', 2, NULL, 'Energy Flow and Productivity', 'easy', '2'),
  ('ess_m2_44', 'The Figure shows a field with small yellow and medium blue flowers, as well as some four-leaf clover. Calculate the percentage frequency of the small yellow flowers.', '["15%","17%","19%","32%"]', 0, NULL, 'Species and Ecosystems', 'easy', '2'),
  ('ess_m2_45', 'Distinguish between transfers and transformations of carbon on the diagram of the carbon cycle. I. II.', '["Transfer","Transfer","Transformation","Transformation"]', 0, NULL, 'Nutrient Cycling', 'easy', '2'),
  ('ess_m2_46', 'Determine the food chain that might be represented by this pyramid.', '["phytoplankton","grass","tree","blueberry bushes"]', 2, NULL, 'Energy Flow and Productivity', 'medium', '2'),
  ('ess_m2_47', 'The Figure shows the population density cycles of a predator and prey. Describe the relationship between the two animals.', '["No relationship between predator and prey","Negative feedback maintaining a stable equilibrium","Positive feedback maintaining a stable equilibrium","Positive feedback going away from the initial equilibrium"]', 1, NULL, 'Species and Ecosystems', 'medium', '2'),
  ('ess_m2_48', 'The Figure shows the flow of energy per unit area per year in arbitrary units. Gross production is the total kJ obtained through photosynthesis, and net production is the kJ remaining after respiration. Calculate the percentage of net production that is lost to decomposers by primary consumers.', '["100","75","50","25"]', 1, NULL, 'Energy Flow and Productivity', 'medium', '2'),
  ('ess_m2_49', 'Calculate the percentage flow of net primary productivity (NPP) from producers to tertiary consumers.', '["0.27%","2.70%","0.10%","1.00%"]', 0, NULL, 'Energy Flow and Productivity', 'medium', '2'),
  ('ess_m2_50', 'Identify the statement that is not true of denitrifying bacteria.', '["Denitrifying bacteria are found in waterlogged soils.","Denitrifying bacteria reduce nitrate (NO","Denitrifying bacteria are involved in nitrogen fixation.","Denitrifying bacteria are involved in adding small amounts of nitrogen to the atmosphere."]', 2, NULL, 'Nutrient Cycling', 'medium', '2'),
  ('ess_m2_51', 'Identify which of the following is not a human-induced effect on the nitrogen cycle.', '["Fixation of nitrogen for the production of fertilizers.","Eutrophication of freshwater bodies.","Burning of fossil fuels releases gases that can cause acid rain.","Uptake of nutrients from the soil by specialized bacteria."]', 3, NULL, 'Nutrient Cycling', 'medium', '2'),
  ('ess_m2_52', 'State which is not a description of the rainforest biome.', '["The biome is found in equatorial regions.","Not much light can penetrate the canopy.","Many trees have deep root systems to support the tall trees.","Animal life is extremely diverse, as seen by the numbers of insects, reptiles and amphibians among others."]', 2, NULL, 'Communities and Biomes', 'medium', '2'),
  ('ess_m2_53', 'An entomologist used a series of insect traps to capture specimens of beetle A. On the first day, 1656 insects were caught, of which 324 were beetle A and were marked. The next day the traps held 1185 insects, of which 21 were marked individuals out of a total of 469 of this species. Estimate the size of the population of beetle A using the Lincoln index.', '["7,236","15","93,446","30"]', 0, NULL, 'Species and Ecosystems', 'medium', '2'),
  ('ess_m2_54', 'Wolves occur naturally in North America and Eurasia. Wolves prey on wild animals such as deer, boar and hares, keeping their population numbers in check. Identify a factor that may limit the growth of the wolf population in The Netherlands.', '["Abundance of prey.","Hunting by humans.","Territory to roam.","Reproductive rate."]', 2, NULL, 'Communities and Biomes', 'medium', '2'),
  ('ess_m2_55', 'Identify the process that is represented by the Figure showing the build-up of toxins in a food chain.', '["Bioaccumulation","Eutrophication","Acidification","Biomagnification"]', 3, NULL, 'Communities and Biomes', 'medium', '2'),
  ('ess_m2_56', 'List the statements that are true about Dichlorodiphenyltrichloroethane (DDT): I. DDT has saved millions of lives in the battle against malaria. II. DDT is biomagnified along a food chain but does not bioaccumulate. III. DDT is a persistent organic pollutant (POP) that has been used effectively as an insecticide.', '["I only","I and III only","II and III only","I, II and III"]', 1, NULL, 'Communities and Biomes', 'medium', '2'),
  ('ess_m2_57', 'A student set up an aquatic mesocosm using a commercially available seawater-filled glass orb, which included algae, shrimp, some corals and gravel. Which of the following statements are true? I. The algae are autotrophs, produce carbon compounds and provide oxygen for organisms in the mesocosm II. Saprotrophs present in the water and gravel help to recycle nutrients found in dead organisms III. Herbivores usually present in a natural ecosystem can be excluded in the mesocosm', '["I only","I and II only","II and III only","I, II and III"]', 3, NULL, 'Species and Ecosystems', 'medium', '2'),
  ('ess_m2_58', 'If the sun provided 5 million joules of energy to the phytoplankton, estimate how much energy the small fish would be able to provide to larger fish that might consume them.', '["5000J","50000J","500J","50J"]', 0, NULL, 'Energy Flow and Productivity', 'medium', '2'),
  ('ess_m2_59', 'Deduce which organism in the food web is not assigned to its correct mode of nutrition.', '["Bacteria and fungi are decomposers","Birds are primary consumers","Nematode is a secondary consumer","An arthropod that eats the smaller arthropod is a predator"]', 1, NULL, 'Energy Flow and Productivity', 'medium', '2'),
  ('ess_m2_60', 'The estimated population of Luxembourg is 640,000, while Brazil is estimated at 214 million. Using these estimates and the Figure above, calculate the total CO2 emissions in tonnes for both countries.', '["1,779,200","1,734,400","2.78","278,000,000"]', 0, NULL, 'Nutrient Cycling', 'medium', '2'),
  ('ess_m2_61', 'Use the formula to calculate Simpson''s Diversity Index for the north sample.', '["6.0","5.0","0.20","0.17"]', 1, NULL, 'Species and Ecosystems', 'medium', '2'),
  ('ess_m2_62', 'Identify the correct statement related to diversity in an ecosystem.', '["An increase in genetic diversity in an ecosystem leads to an increase in species diversity.","An increase in species diversity in an ecosystem leads to an increase in habitat diversity.","An increase in genetic diversity in an ecosystem leads to an increase in habitat diversity.","An increase in habitat diversity in an ecosystem leads to an increase in species diversity."]', 3, NULL, 'Species and Ecosystems', 'medium', '2'),
  ('ess_m2_63', 'Calculate the percentage increase from the month with the lowest rainfall to the month with the highest rainfall in Rome, Italy.', '["501%","95.2%","83.4%","16.6%"]', 0, NULL, 'Communities and Biomes', 'medium', '2'),
  ('ess_m2_64', 'Identify the biomes that are likely to be shown in the graph. Biome A Biome B', '["Rainforest","Rainforest","Desert","Tundra"]', 3, NULL, 'Communities and Biomes', 'medium', '2'),
  ('ess_m2_65', 'Identify the graph that best reflects the growth of a population over time.', '["A.","B.","",""]', 1, NULL, 'Communities and Biomes', 'hard', '2'),
  ('ess_m2_66', 'Identify which of the following is an example of a transformation.', '["Water is lost from plants by the process of transpiration (evaporation from the leaves).","During photosynthesis, carbon dioxide moves into the leaves of the plants.","Producers are consumed by herbivores in ecosystems.","Glucose and other sugars made in the leaves are transported to other parts of the plant."]', 0, NULL, 'Nutrient Cycling', 'medium', '2'),
  ('ess_m2_67', 'Identify the trophic classification of creatures that would best fit in the green box in the figure.', '["Heterotrophs","Chemoautotrophs","Photoautotrophs","Tertiary Consumers"]', 1, NULL, 'Energy Flow and Productivity', 'hard', '2'),
  ('ess_m2_68', 'Identify the statement that does not accurately describe a food web.', '["The trophic level of the primary producers has the highest species abundance.","Both aquatic and terrestrial systems have similar chain lengths.","Decomposers break down dead organisms from all trophic levels of a food web.","Many different herbivores may feed on the same plant species."]', 1, NULL, 'Energy Flow and Productivity', 'hard', '2'),
  ('ess_m2_69', 'List the changes in biodiversity, GPP and NPP as primary succession progresses from a pioneer community to a climax community.', '["Increases","Decreases","Increases","Increases"]', 2, NULL, 'Succession', 'hard', '2'),
  ('ess_m2_70', 'To increase the reliability of the data, it is important to take multiple readings of the same factor. Identify the factor that would require the most readings to ensure its reliability.', '["Early morning air temperature in a cloud forest in Ecuador in March","Particle size of the soil on the savanna in the Serengeti, Tanzania","Leaf size of oak trees (","Flow velocity of the Mekong River at the Myanmar, Laos, Thailand tripoint in November"]', 2, NULL, 'Species and Ecosystems', 'hard', '2'),
  ('ess_m2_71', 'CO2 emissions from deforestation for food production from 2010-2014. Suggest which of the following statements are supported by the information in the graph. I. China and the U.S. had low CO2 emissions between 2010 and 2014. II. Brazil and Luxembourg had high CO2 emissions between 2010 and 2014. III. France and Spain had the same amount of CO2 emissions due to deforestation for food production during that time.', '["All statements are supported by the information.","Statements II and III are supported by the information.","Only statement III is supported by the information.","None of the statements are supported by the information."]', 3, NULL, 'Nutrient Cycling', 'hard', '2'),
  ('ess_m2_72', 'An experiment was carried out using bottles with an Elodea plant in water. One was kept in light and the other in darkness. The dissolved oxygen values were obtained at the beginning of the experiment and after two days in both bottles. Calculate values for GPP, NPP and R from the simplified data given.', '["800","600","600","800"]', 1, NULL, 'Energy Flow and Productivity', 'hard', '2'),
  ('ess_m2_73', 'Identify which of the following statements is not correct in describing the changes in productivity during primary succession.', '["In the first stages of primary succession, due to minimal nutrient levels, GPP is low.","In the intermediate stages of succession, GSP increases as consumers join the food chain.","GPP continues to increase throughout the stages of succession due to improved soil fertility.","In the final or climax stages, biomass continues to increase due to increased productivity."]', 3, NULL, 'Succession', 'hard', '2'),
  ('ess_m2_74', 'Willow Creek runs north to south past Happy City. Ecologists want to investigate the effect the city is having on the diversity of the Willow Creek ecosystem. Calculate Simpson''s Diversity Index for the locations north and south of the city to determine the effect of the city on the creek.', '["Happy City is having a positive impact on creek diversity.","Happy City is having a small negative impact on creek diversity.","Happy City is having a large negative impact on creek diversity.","Happy City is having no impact on creek diversity."]', 0, NULL, 'Species and Ecosystems', 'hard', '2'),
  ('ess_m2_75', 'Using the Figure, calculate a net flow of carbon.', '["Vegetation/soil releases 1","Vegetation/soil absorbs 1","Marine biota gain 11","Marine biota lose 11"]', 1, NULL, 'Nutrient Cycling', 'hard', '2');
